var suggestions=document.getElementById('suggestions'),search=document.getElementById('search');search!==null&&document.addEventListener('keydown',inputFocus);function inputFocus(a){a.ctrlKey&&a.key==='/'&&(a.preventDefault(),search.focus()),a.key==='Escape'&&(search.blur(),suggestions.classList.add('d-none'))}document.addEventListener('click',function(a){var b=suggestions.contains(a.target);b||suggestions.classList.add('d-none')}),document.addEventListener('keydown',suggestionFocus);function suggestionFocus(c){const d=suggestions.classList.contains('d-none');if(d)return;const a=[...suggestions.querySelectorAll('a')];if(a.length===0)return;const b=a.indexOf(document.activeElement);if(c.key==="ArrowUp"){c.preventDefault();const d=b>0?b-1:0;a[d].focus()}else if(c.key==="ArrowDown"){c.preventDefault();const d=b+1<a.length?b+1:b;a[d].focus()}}(function(){var a=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:'id',store:["href","title","description"],index:["title","description","content"]}});a.add({id:0,href:"/blog/nlp-series-part-2-word2vec-skip-gram-negative-sampling/",title:"NLP Series [Part 2] · Word2Vec-Skip-Gram-Negative-Sampling",description:"Continuing with our previous post, we explore Word2Vec skip-gram model with negative sampling.",content:"Most of the steps are similar to our notebook on Word2Vec without negative sampling. The key changes happen with the dataset where we provide a list of indices for negative sample for each forward pass as well as the loss function.\nIn this notebook, we will train a Word2Vec skip-gram model with negative sampling from scratch on some text and inspect the trained embeddings at the end.\nThe architecture we define later will enable us to learn a distributed representation for each word/token in our corpus. The key idea being, we can represent a work by adding contextual information to it. Context here is the neighbouring words around a word/token of interest to us.\nfrom collections import Counter from random import sample import re from typing import List, Tuple import numpy as np import requests from sklearn.metrics.pairwise import cosine_similarity import torch import torch.nn as nn from torch.utils.data import DataLoader, Dataset  The whole process can be broken down into the following key steps:\n Fetch and process text using TextProcessor. fetch_text() fetches the texts directly from urls containing our text data. process_text() applies basic pre-procesing steps to the text and creats tokens using white space tokenization. prepare_vocab() creates token to index mapping and vice versa. Create torch Dataset and Dataloader where each index in the dataset will be a tuple, (center_word_ix, context_word_ix); i.e. pairs of indices of center word and context based on a pre defined window size. Create our SkipGramModel model based on the torch.nn.Module. Define our loss function, optimizer and scheduler. Train the model for a certain number of epochs.  Finally, we will create a similarity matrix(cosine similarity) using the trained embeddings and explore similar embeddings for some word query.\nStep 1. Fetch and prepare the data # We will be using the first four Harry Potter books.\nBASE_URL = \u0026quot;https://raw.githubusercontent.com/formcept/whiteboard/master/nbviewer/notebooks/data/harrypotter\u0026quot; BOOK_URLS = [ f\u0026quot;{BASE_URL}/Book%201%20-%20The%20Philosopher's%20Stone.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%202%20-%20The%20Chamber%20of%20Secrets.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%203%20-%20The%20Prisoner%20of%20Azkaban.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%204%20-%20The%20Goblet%20of%20Fire.txt\u0026quot; ]  class TextProcessor: def __init__(self, urls: List[str]): self.urls = urls def fetch_text(self): self.text = \u0026quot;\u0026quot; for i, url in enumerate(self.urls): r = requests.get(url) r.status_code self.text += \u0026quot;\\n\\n\\n\u0026quot; + r.text print(f\u0026quot;Fetched {i+1}/{len(self.urls)} urls ...\u0026quot;) def process_text(self): print(\u0026quot;Processing text ...\u0026quot;) sentences = re.split(\u0026quot;\\n{2,}\u0026quot;, self.text) print(f\u0026quot; \u0026gt; {len(sentences)} sentences\u0026quot;) self.clean_sentences = [] for txt in sentences: txt = txt.strip().lower() txt = txt.replace(\u0026quot;\\n\u0026quot;, \u0026quot;\u0026quot;) txt = \u0026quot; \u0026quot;.join(re.findall(\u0026quot;\\w+\u0026quot;, txt)) if txt: self.clean_sentences.append(txt) # Tokens and token counter will be used later to create a vocabulary for # us which will be used to map words/tokens to indices and vice versa, to # create training data and recreate the texts from predictions respectively. print(f\u0026quot; \u0026gt; {len(sentences)} filtered sentences\u0026quot;) tokens = \u0026quot; \u0026quot;.join(self.clean_sentences).split(\u0026quot; \u0026quot;) print(f\u0026quot; \u0026gt; {len(tokens)} tokens\u0026quot;) self.token_counter = Counter(tokens) print(f\u0026quot; \u0026gt; {len(self.token_counter)} unique tokens\u0026quot;) def prepare_vocab(self, min_count: int): # min_count is the minimum number of times a token should appear in the # text to be considered in the vocabulary else they are assigned to a # default index which is equal to `len(vocab)`. self.w2ix = {} for i, (token, count) in enumerate( self.token_counter.most_common(len(self.token_counter)) ): if count \u0026lt; min_count: break else: self.w2ix[token] = i self.ix2w = {ix: w for w, ix in self.w2ix.items()} # assign default index to rest of the tokens n = len(self.w2ix) for token, _ in self.token_counter.most_common(len(self.token_counter)): if token not in self.w2ix: self.w2ix[token] = n self.ix2w[n] = \u0026quot;\u0026lt;unk\u0026gt;\u0026quot; self.ixs = list(self.ix2w.keys()) self.vocab_size = n + 1 print(f\u0026quot;Vocab size: {self.vocab_size}\u0026quot;)  text_processor = TextProcessor(BOOK_URLS)  text_processor.fetch_text()  Fetched 1/4 urls ... Fetched 2/4 urls ... Fetched 3/4 urls ... Fetched 4/4 urls ...  text_processor.process_text()  Processing text ... \u0026gt; 20033 sentences \u0026gt; 20033 filtered sentences \u0026gt; 501854 tokens \u0026gt; 15078 unique tokens  text_processor.prepare_vocab(min_count=20)  Vocab size: 2103  Step 2. Prepare the torch Dataset and Dataloader # The Dataloader will enable us to send data in batches during the forward pass of the model training.\nN_NEG_SAMPLES = 20  class HarryPotterDataset(Dataset): def __init__(self, text_processor: TextProcessor, window_size: int=3): self.data = [] for txt in text_processor.clean_sentences: splits = txt.split(\u0026quot; \u0026quot;) for i in range(window_size, len(splits) -1): center_word = splits[i] window_words = splits[i-window_size:i]+splits[i+1:i+window_size+1] for context in window_words: # Each data point under self.data will be a tuple with index 0 # containing the index(w2ix) for center_word and # index 1 containing the index(w2ix) for context_word and # index 2 containing negative samples self.data.append(( text_processor.w2ix[center_word], text_processor.w2ix[context], sample(text_processor.ixs, N_NEG_SAMPLES) )) def __getitem__(self, ix: int): return self.data[ix] def __len__(self): return len(self.data)  The Dataset essentially contains indexes of pairs of center word and a context word.\ndataset = HarryPotterDataset(text_processor, 3) len(dataset)  2489461  def collate_fn(collate_fn_input: List[Tuple]): return ( torch.LongTensor([i[0] for i in collate_fn_input]), # center word torch.LongTensor([i[1] for i in collate_fn_input]), # context word torch.LongTensor([i[2] for i in collate_fn_input]) # negative samples )  dataloader = DataLoader(dataset, batch_size=64, collate_fn=collate_fn, shuffle=True)  Step 3. Create the Word2Vec model using torch.nn.Module. # class SkipGramModel(nn.Module): def __init__(self, vocab_size: int, embedding_size: int=50): super().__init__() self.u_embeddings = nn.Embedding(vocab_size, embedding_size) self.v_embeddings = nn.Embedding(vocab_size, embedding_size) def forward(self, pos_u, pos_v, neg_v): losses = [] emb_u = self.u_embeddings(pos_u) emb_v = self.v_embeddings(pos_v) score = torch.mul(emb_u, emb_v).squeeze() score = torch.sum(score, dim=1) score = nn.functional.logsigmoid(score) losses.append(sum(score)) neg_emb_v = self.v_embeddings(neg_v) neg_score = torch.bmm(neg_emb_v, emb_u.unsqueeze(2)).squeeze() neg_score = torch.sum(neg_score, dim=1) neg_score = nn.functional.logsigmoid(-1 * neg_score) losses.append(sum(neg_score)) return -1 * sum(losses)  Embedding is nothing but \u0026ldquo;A simple lookup table that stores embeddings of a fixed dictionary and size\u0026rdquo; - pytorch documentation.\nThe modified loss function for negative sampling is:   Source: https://lena-voita.github.io/nlp_course/word_embeddings.html\nIn each forward pass we:\n Pass indices of center word as input param pos_u. These indices are looked up in the self.u_embeddings table. pos_v is the index for context word and self.v_embeddings is the associated embedding table. score is the first part of the loss function, i.e. the component we need to increase(similarity between the center and context vectors) neg_score is the second part of the loss function, i.e. the component we need to decrease(similarity between the center embedding and negative embeddings)  A trained model should output high values for the context indices for a given center word.\ndevice = torch.device(\u0026quot;cuda\u0026quot; if torch.cuda.is_available() else \u0026quot;cpu\u0026quot;) model = SkipGramModel(text_processor.vocab_size, embedding_size=30).to(device)  Step 4. Define our loss function, optimizer and scheduler # optimizer = torch.optim.Adam(model.parameters(), lr=0.005) scheduler = torch.optim.lr_scheduler.StepLR(optimizer, step_size=8, gamma=0.5)  N_EPOCHS = 24 # since we have a small dataset, more epochs STEP_TO_LOG = 10000 # print the loss every x step of the DataLoader  Step 5. Train the model # epoch_losses = [] batch_losses = [] for epoch in range(N_EPOCHS): losses = [] for i, data in enumerate(dataloader): inputs = data[0].to(device) outputs = data[1].to(device) neg_samples = data[2].to(device) loss = model(inputs, outputs, neg_samples) losses.append(loss.item()) loss.backward() optimizer.step() optimizer.zero_grad() if i % STEP_TO_LOG == 0: print(f\u0026quot;epoch {epoch + 1}; steps={i:\u0026gt;5}/{len(dataloader)}; loss={loss:\u0026lt;.5f}\u0026quot;) scheduler.step() batch_losses += losses epoch_losses.append(np.mean(losses)) print(f\u0026quot;epoch {epoch + 1} ; lr={scheduler._last_lr[0]}; loss={loss:\u0026lt;.5f}\\n\u0026quot;)  epoch 1; steps= 0/38898; loss=635.80212 epoch 1; steps=10000/38898; loss=22.34518 epoch 1; steps=20000/38898; loss=33.05764 epoch 1; steps=30000/38898; loss=25.38408 epoch 1 ; lr=0.005; loss=23.79806 epoch 2; steps= 0/38898; loss=16.68314 epoch 2; steps=10000/38898; loss=16.79985 epoch 2; steps=20000/38898; loss=14.40299 epoch 2; steps=30000/38898; loss=27.52887 epoch 2 ; lr=0.005; loss=15.07795 epoch 3; steps= 0/38898; loss=19.86652 epoch 3; steps=10000/38898; loss=12.42353 epoch 3; steps=20000/38898; loss=27.75500 epoch 3; steps=30000/38898; loss=11.13718 epoch 3 ; lr=0.005; loss=23.87044 epoch 4; steps= 0/38898; loss=22.07467 epoch 4; steps=10000/38898; loss=19.45840 epoch 4; steps=20000/38898; loss=13.68762 epoch 4; steps=30000/38898; loss=13.98966 epoch 4 ; lr=0.005; loss=15.99264 epoch 5; steps= 0/38898; loss=16.17529 epoch 5; steps=10000/38898; loss=11.52369 epoch 5; steps=20000/38898; loss=19.73762 epoch 5; steps=30000/38898; loss=15.30890 epoch 5 ; lr=0.005; loss=12.37201 epoch 6; steps= 0/38898; loss=36.69007 epoch 6; steps=10000/38898; loss=15.42795 epoch 6; steps=20000/38898; loss=19.52234 epoch 6; steps=30000/38898; loss=27.82760 epoch 6 ; lr=0.005; loss=9.62671 epoch 7; steps= 0/38898; loss=18.23301 epoch 7; steps=10000/38898; loss=30.61018 epoch 7; steps=20000/38898; loss=19.27209 epoch 7; steps=30000/38898; loss=11.94759 epoch 7 ; lr=0.005; loss=11.64728 epoch 8; steps= 0/38898; loss=16.93320 epoch 8; steps=10000/38898; loss=9.60485 epoch 8; steps=20000/38898; loss=30.24725 epoch 8; steps=30000/38898; loss=14.01960 epoch 8 ; lr=0.0025; loss=15.27110 epoch 9; steps= 0/38898; loss=17.77393 epoch 9; steps=10000/38898; loss=19.11106 epoch 9; steps=20000/38898; loss=6.39290 epoch 9; steps=30000/38898; loss=36.18101 epoch 9 ; lr=0.0025; loss=22.13097 epoch 10; steps= 0/38898; loss=21.57537 epoch 10; steps=10000/38898; loss=17.62466 epoch 10; steps=20000/38898; loss=20.33191 epoch 10; steps=30000/38898; loss=14.83914 epoch 10 ; lr=0.0025; loss=9.07016 epoch 11; steps= 0/38898; loss=9.25244 epoch 11; steps=10000/38898; loss=15.08578 epoch 11; steps=20000/38898; loss=12.67025 epoch 11; steps=30000/38898; loss=14.59466 epoch 11 ; lr=0.0025; loss=22.12947 epoch 12; steps= 0/38898; loss=8.33545 epoch 12; steps=10000/38898; loss=26.42342 epoch 12; steps=20000/38898; loss=18.76328 epoch 12; steps=30000/38898; loss=16.90550 epoch 12 ; lr=0.0025; loss=22.55820 epoch 13; steps= 0/38898; loss=10.51294 epoch 13; steps=10000/38898; loss=14.41905 epoch 13; steps=20000/38898; loss=5.90636 epoch 13; steps=30000/38898; loss=20.60696 epoch 13 ; lr=0.0025; loss=8.38153 epoch 14; steps= 0/38898; loss=14.23109 epoch 14; steps=10000/38898; loss=17.03224 epoch 14; steps=20000/38898; loss=8.77814 epoch 14; steps=30000/38898; loss=46.80190 epoch 14 ; lr=0.0025; loss=14.82973 epoch 15; steps= 0/38898; loss=11.28982 epoch 15; steps=10000/38898; loss=9.09633 epoch 15; steps=20000/38898; loss=17.57424 epoch 15; steps=30000/38898; loss=12.01542 epoch 15 ; lr=0.0025; loss=6.22763 epoch 16; steps= 0/38898; loss=9.32489 epoch 16; steps=10000/38898; loss=18.66871 epoch 16; steps=20000/38898; loss=18.52152 epoch 16; steps=30000/38898; loss=9.81702 epoch 16 ; lr=0.00125; loss=11.27573 epoch 17; steps= 0/38898; loss=16.88287 epoch 17; steps=10000/38898; loss=19.38610 epoch 17; steps=20000/38898; loss=13.58566 epoch 17; steps=30000/38898; loss=12.11638 epoch 17 ; lr=0.00125; loss=3.66489 epoch 18; steps= 0/38898; loss=10.56005 epoch 18; steps=10000/38898; loss=23.82092 epoch 18; steps=20000/38898; loss=15.58498 epoch 18; steps=30000/38898; loss=10.08900 epoch 18 ; lr=0.00125; loss=23.05105 epoch 19; steps= 0/38898; loss=10.45432 epoch 19; steps=10000/38898; loss=13.71866 epoch 19; steps=20000/38898; loss=12.53261 epoch 19; steps=30000/38898; loss=11.18567 epoch 19 ; lr=0.00125; loss=10.93487 epoch 20; steps= 0/38898; loss=8.09276 epoch 20; steps=10000/38898; loss=11.03898 epoch 20; steps=20000/38898; loss=13.74371 epoch 20; steps=30000/38898; loss=15.99348 epoch 20 ; lr=0.00125; loss=12.07587 epoch 21; steps= 0/38898; loss=8.27782 epoch 21; steps=10000/38898; loss=24.72760 epoch 21; steps=20000/38898; loss=9.07991 epoch 21; steps=30000/38898; loss=10.21649 epoch 21 ; lr=0.00125; loss=11.43991 epoch 22; steps= 0/38898; loss=6.63023 epoch 22; steps=10000/38898; loss=21.51781 epoch 22; steps=20000/38898; loss=15.30544 epoch 22; steps=30000/38898; loss=10.24912 epoch 22 ; lr=0.00125; loss=10.69229 epoch 23; steps= 0/38898; loss=15.57696 epoch 23; steps=10000/38898; loss=10.21371 epoch 23; steps=20000/38898; loss=7.57503 epoch 23; steps=30000/38898; loss=10.63820 epoch 23 ; lr=0.00125; loss=33.97425 epoch 24; steps= 0/38898; loss=14.56317 epoch 24; steps=10000/38898; loss=20.08979 epoch 24; steps=20000/38898; loss=13.44788 epoch 24; steps=30000/38898; loss=11.48513 epoch 24 ; lr=0.000625; loss=14.42273  weights = model.u_embeddings.weight.detach().cpu().numpy() weights.shape  (2103, 30)  Step 6. Create the similarity matrix # similarity = cosine_similarity(weights, weights)  def get_similar_words(input_word: str, n: int): if input_word not in text_processor.w2ix: print(\u0026quot;word not in vocab\u0026quot;) else: input_word_ix = text_processor.w2ix[input_word] similarity_vector = similarity[input_word_ix] most_similar_ixs = np.argsort(similarity_vector)[-n:][::-1] most_similar_words = [(text_processor.ix2w[ix], similarity_vector[ix]) for ix in most_similar_ixs] print(input_word) for word, score in most_similar_words: print(f\u0026quot; \u0026gt; {word}, score={score: .2f}\u0026quot;)  Exploring similar embeddings for some queries \u0026hellip;\nget_similar_words(\u0026quot;snape\u0026quot;, 10)  snape \u0026gt; snape, score= 1.00 \u0026gt; dumbledore, score= 0.76 \u0026gt; trelawney, score= 0.72 \u0026gt; professor, score= 0.68 \u0026gt; moody, score= 0.66 \u0026gt; lupin, score= 0.64 \u0026gt; serious, score= 0.62 \u0026gt; he, score= 0.61 \u0026gt; everyone, score= 0.60 \u0026gt; severus, score= 0.60  get_similar_words(\u0026quot;vernon\u0026quot;, 10)  vernon \u0026gt; vernon, score= 1.00 \u0026gt; uncle, score= 0.98 \u0026gt; petunia, score= 0.75 \u0026gt; dudley, score= 0.75 \u0026gt; aunt, score= 0.73 \u0026gt; mrs, score= 0.63 \u0026gt; dursleys, score= 0.60 \u0026gt; george, score= 0.59 \u0026gt; surprise, score= 0.59 \u0026gt; ron, score= 0.57  get_similar_words(\u0026quot;muggle\u0026quot;, 10)  muggle \u0026gt; muggle, score= 1.00 \u0026gt; magic, score= 0.76 \u0026gt; do, score= 0.74 \u0026gt; hope, score= 0.74 \u0026gt; loads, score= 0.69 \u0026gt; act, score= 0.69 \u0026gt; you, score= 0.69 \u0026gt; haven, score= 0.68 \u0026gt; ve, score= 0.68 \u0026gt; well, score= 0.66  get_similar_words(\u0026quot;harry\u0026quot;, 10)  harry \u0026gt; harry, score= 1.00 \u0026gt; he, score= 0.83 \u0026gt; ron, score= 0.82 \u0026gt; him, score= 0.79 \u0026gt; hermione, score= 0.74 \u0026gt; as, score= 0.74 \u0026gt; but, score= 0.73 \u0026gt; then, score= 0.71 \u0026gt; she, score= 0.70 \u0026gt; it, score= 0.69  get_similar_words(\u0026quot;granger\u0026quot;, 10)  granger \u0026gt; granger, score= 1.00 \u0026gt; telling, score= 0.62 \u0026gt; pretty, score= 0.61 \u0026gt; miss, score= 0.58 \u0026gt; remembered, score= 0.57 \u0026gt; sprout, score= 0.55 \u0026gt; pansy, score= 0.54 \u0026gt; thoroughly, score= 0.54 \u0026gt; joined, score= 0.53 \u0026gt; ah, score= 0.52  get_similar_words(\u0026quot;slytherin\u0026quot;, 10)  slytherin \u0026gt; slytherin, score= 1.00 \u0026gt; seeker, score= 0.67 \u0026gt; quaffle, score= 0.66 \u0026gt; team, score= 0.64 \u0026gt; gryffindors, score= 0.63 \u0026gt; cheering, score= 0.63 \u0026gt; ravenclaw, score= 0.62 \u0026gt; lee, score= 0.61 \u0026gt; gryffindor, score= 0.58 \u0026gt; other, score= 0.58  get_similar_words(\u0026quot;malfoy\u0026quot;, 10)  malfoy \u0026gt; malfoy, score= 1.00 \u0026gt; ron, score= 0.64 \u0026gt; mr, score= 0.61 \u0026gt; draco, score= 0.61 \u0026gt; then, score= 0.61 \u0026gt; without, score= 0.60 \u0026gt; harry, score= 0.57 \u0026gt; he, score= 0.56 \u0026gt; karkaroff, score= 0.56 \u0026gt; diggory, score= 0.56  The model convergance was not as good as our previous training without negative sampling and some of the similarity results on manual inspection look a little off. There could be a problem with our model or the amount of training we did. We did not exactly follow the steps mentioned in the original paper to be honest.\nStill, I just wanted to cover this for the sake of completeness. Up next, we will move onto sub word embedding techniques which would allow us to handle out of vocab tokens/words.\n"}).add({id:1,href:"/blog/nlp-series-part-1-word2vec-skip-gram/",title:"NLP Series [Part 1] · Word2Vec-Skip-Gram",description:"We will take a walk down the memory lane and visit the awesome Word2Vec.",content:"In this notebook, we will train a Word2Vec skip-gram model from scratch on some text and inspect the trained embeddings at the end.\nThe architecture we define later will enable us to learn a distributed representation for each word/token in our corpus. The key idea being, we can represent a work by adding contextual information to it. Context here is the neighbouring words around a word/token of interest to us.\nfrom collections import Counter import re from typing import List import numpy as np import requests from sklearn.metrics.pairwise import cosine_similarity import torch import torch.nn as nn from torch.utils.data import DataLoader, Dataset  The whole process can be broken down into the following key steps:\n Fetch and process text using TextProcessor. fetch_text() fetches the texts directly from urls containing our text data. process_text() applies basic pre-procesing steps to the text and creats tokens using white space tokenization. prepare_vocab() creates token to index mapping and vice versa. Create torch Dataset and Dataloader where each index in the dataset will be a tuple, (center_word_ix, context_word_ix); i.e. pairs of indices of center word and context based on a pre defined window size. Create our SkipGramModel model based on the torch.nn.Module. Define our loss function, optimizer and scheduler. Train the model for a certain number of epochs.  Finally, we will create a similarity matrix(cosine similarity) using the trained embeddings and explore similar embeddings for some word query.\nStep 1. Fetch and prepare the data # We will be using the first four Harry Potter books.\nBASE_URL = \u0026quot;https://raw.githubusercontent.com/formcept/whiteboard/master/nbviewer/notebooks/data/harrypotter\u0026quot; BOOK_URLS = [ f\u0026quot;{BASE_URL}/Book%201%20-%20The%20Philosopher's%20Stone.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%202%20-%20The%20Chamber%20of%20Secrets.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%203%20-%20The%20Prisoner%20of%20Azkaban.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%204%20-%20The%20Goblet%20of%20Fire.txt\u0026quot; ]  class TextProcessor: def __init__(self, urls: List[str]): self.urls = urls def fetch_text(self): self.text = \u0026quot;\u0026quot; for i, url in enumerate(self.urls): r = requests.get(url) r.status_code self.text += \u0026quot;\\n\\n\\n\u0026quot; + r.text print(f\u0026quot;Fetched {i+1}/{len(self.urls)} urls ...\u0026quot;) def process_text(self): print(\u0026quot;Processing text ...\u0026quot;) sentences = re.split(\u0026quot;\\n{2,}\u0026quot;, self.text) print(f\u0026quot; \u0026gt; {len(sentences)} sentences\u0026quot;) self.clean_sentences = [] for txt in sentences: txt = txt.strip().lower() txt = txt.replace(\u0026quot;\\n\u0026quot;, \u0026quot;\u0026quot;) txt = \u0026quot; \u0026quot;.join(re.findall(\u0026quot;\\w+\u0026quot;, txt)) if txt: self.clean_sentences.append(txt) # Tokens and token counter will be used later to create a vocabulary for # us which will be used to map words/tokens to indices and vice versa, to # create training data and recreate the texts from predictions respectively. print(f\u0026quot; \u0026gt; {len(sentences)} filtered sentences\u0026quot;) tokens = \u0026quot; \u0026quot;.join(self.clean_sentences).split(\u0026quot; \u0026quot;) print(f\u0026quot; \u0026gt; {len(tokens)} tokens\u0026quot;) self.token_counter = Counter(tokens) print(f\u0026quot; \u0026gt; {len(self.token_counter)} unique tokens\u0026quot;) def prepare_vocab(self, min_count: int): # min_count is the minimum number of times a token should appear in the # text to be considered in the vocabulary else they are assigned to a # default index which is equal to `len(vocab)`. self.w2ix = {} for i, (token, count) in enumerate( self.token_counter.most_common(len(self.token_counter)) ): if count \u0026lt; min_count: break else: self.w2ix[token] = i self.ix2w = {ix: w for w, ix in self.w2ix.items()} # assign default index to rest of the tokens n = len(self.w2ix) for token, _ in self.token_counter.most_common(len(self.token_counter)): if token not in self.w2ix: self.w2ix[token] = n self.ix2w[n] = \u0026quot;\u0026lt;unk\u0026gt;\u0026quot; self.vocab_size = n + 1 print(f\u0026quot;Vocab size: {self.vocab_size}\u0026quot;)  text_processor = TextProcessor(BOOK_URLS)  text_processor.fetch_text()  Fetched 1/4 urls ... Fetched 2/4 urls ... Fetched 3/4 urls ... Fetched 4/4 urls ...  text_processor.process_text()  Processing text ... \u0026gt; 20033 sentences \u0026gt; 20033 filtered sentences \u0026gt; 501854 tokens \u0026gt; 15078 unique tokens  text_processor.prepare_vocab(min_count=20)  Vocab size: 2103  Step 2. Prepare the torch Dataset and Dataloader # The Dataloader will enable us to send data in batches during the forward pass of the model training.\nclass HarryPotterDataset(Dataset): def __init__(self, text_processor: TextProcessor, window_size: int=3): self.data = [] for txt in text_processor.clean_sentences: splits = txt.split(\u0026quot; \u0026quot;) for i in range(window_size, len(splits) -1): center_word = splits[i] window_words = splits[i-window_size:i]+splits[i+1:i+window_size+1] for context in window_words: # Each data point under self.data will be a tuple with index 0 # containing the index(w2ix) for center_word and # index 1 containing the index(w2ix) for context_word self.data.append((text_processor.w2ix[center_word], text_processor.w2ix[context])) def __getitem__(self, ix: int): return self.data[ix] def __len__(self): return len(self.data)  dataset = HarryPotterDataset(text_processor, 3) len(dataset)  dataloader = DataLoader(dataset, batch_size=64, shuffle=True)  Step 3. Create the Word2Vec model using torch.nn.Module # class SkipGramModel(nn.Module): def __init__(self, vocab_size: int, embedding_size: int=50): super().__init__() self.embedding = nn.Embedding(vocab_size, embedding_size) self.linear = nn.Linear(embedding_size, vocab_size) def forward(self, x): return self.linear(self.embedding(x))  The model architecure is Embedding -\u0026gt; Linear -\u0026gt; Softmax.\nEmbedding is nothing but \u0026ldquo;A simple lookup table that stores embeddings of a fixed dictionary and size\u0026rdquo; - pytorch documentation.\nBased on our model architecture, this layer will contain the trained token/word embeddings of interest to us and we will discard the weight matrix from the Linear layer.\nIn each forward pass we:\n Pass indices of center word as input x. These indices are looked up in the self.embedding table. We transform the vector from last step using the Linear layer to get another vector with dimension vocab_size. Finally we apply softmax and calcualte loss.  A trained model should output high values for the context indices for a given center word.\ndevice = torch.device(\u0026quot;cuda\u0026quot; if torch.cuda.is_available() else \u0026quot;cpu\u0026quot;) model = SkipGramModel(text_processor.vocab_size, embedding_size=30).to(device)  Step 4. Define our loss function, optimizer and scheduler # criterion = nn.CrossEntropyLoss() optimizer = torch.optim.Adam(model.parameters(), lr=0.005) scheduler = torch.optim.lr_scheduler.StepLR(optimizer, step_size=5, gamma=0.5)  N_EPOCHS = 20 # Since we have a small dataset, more epochs STEP_TO_LOG = 10000 # Print the loss every x step of the DataLoader  Step 5. Train the model # epoch_losses = [] batch_losses = [] for epoch in range(N_EPOCHS): losses = [] for i, data in enumerate(dataloader): inputs = data[0].long().to(device) outputs = data[1].long().to(device) pred = model(inputs) loss = criterion(pred, outputs) losses.append(loss.item()) loss.backward() optimizer.step() optimizer.zero_grad() if i % STEP_TO_LOG == 0: print(f\u0026quot;epoch {epoch + 1}; steps={i:\u0026gt;5}/{len(dataloader)}; loss={loss:\u0026lt;.5f}\u0026quot;) scheduler.step() batch_losses += losses epoch_losses.append(np.mean(losses)) print(f\u0026quot;epoch {epoch + 1} ; lr={scheduler._last_lr[0]}; loss={loss:\u0026lt;.5f}\\n\u0026quot;)  epoch 1; steps= 0/38898; loss=7.77347 epoch 1; steps=10000/38898; loss=5.24432 epoch 1; steps=20000/38898; loss=5.55209 epoch 1; steps=30000/38898; loss=5.74518 epoch 1 ; lr=0.005; loss=6.44326 epoch 2; steps= 0/38898; loss=5.18774 epoch 2; steps=10000/38898; loss=5.02457 epoch 2; steps=20000/38898; loss=5.71072 epoch 2; steps=30000/38898; loss=5.11149 epoch 2 ; lr=0.005; loss=5.04696 epoch 3; steps= 0/38898; loss=5.76455 epoch 3; steps=10000/38898; loss=5.36094 epoch 3; steps=20000/38898; loss=5.36201 epoch 3; steps=30000/38898; loss=5.52337 epoch 3 ; lr=0.005; loss=6.28578 epoch 4; steps= 0/38898; loss=5.57676 epoch 4; steps=10000/38898; loss=5.22308 epoch 4; steps=20000/38898; loss=5.83870 epoch 4; steps=30000/38898; loss=6.00284 epoch 4 ; lr=0.005; loss=5.36329 epoch 5; steps= 0/38898; loss=5.54562 epoch 5; steps=10000/38898; loss=5.45449 epoch 5; steps=20000/38898; loss=4.99433 epoch 5; steps=30000/38898; loss=5.03800 epoch 5 ; lr=0.0025; loss=5.62579 epoch 6; steps= 0/38898; loss=5.39675 epoch 6; steps=10000/38898; loss=5.96204 epoch 6; steps=20000/38898; loss=5.76479 epoch 6; steps=30000/38898; loss=5.62020 epoch 6 ; lr=0.0025; loss=5.39560 epoch 7; steps= 0/38898; loss=5.03126 epoch 7; steps=10000/38898; loss=5.25755 epoch 7; steps=20000/38898; loss=4.95463 epoch 7; steps=30000/38898; loss=5.79732 epoch 7 ; lr=0.0025; loss=5.09368 epoch 8; steps= 0/38898; loss=5.67842 epoch 8; steps=10000/38898; loss=4.90622 epoch 8; steps=20000/38898; loss=5.59550 epoch 8; steps=30000/38898; loss=5.42461 epoch 8 ; lr=0.0025; loss=5.78050 epoch 9; steps= 0/38898; loss=5.59528 epoch 9; steps=10000/38898; loss=6.03118 epoch 9; steps=20000/38898; loss=5.62938 epoch 9; steps=30000/38898; loss=5.43099 epoch 9 ; lr=0.0025; loss=5.62948 epoch 10; steps= 0/38898; loss=5.33678 epoch 10; steps=10000/38898; loss=5.30591 epoch 10; steps=20000/38898; loss=5.31357 epoch 10; steps=30000/38898; loss=5.81043 epoch 10 ; lr=0.00125; loss=5.45841 epoch 11; steps= 0/38898; loss=5.77081 epoch 11; steps=10000/38898; loss=5.52807 epoch 11; steps=20000/38898; loss=5.80410 epoch 11; steps=30000/38898; loss=5.85639 epoch 11 ; lr=0.00125; loss=5.15784 epoch 12; steps= 0/38898; loss=5.65535 epoch 12; steps=10000/38898; loss=5.69625 epoch 12; steps=20000/38898; loss=5.41546 epoch 12; steps=30000/38898; loss=5.49350 epoch 12 ; lr=0.00125; loss=5.27568 epoch 13; steps= 0/38898; loss=5.40524 epoch 13; steps=10000/38898; loss=5.88747 epoch 13; steps=20000/38898; loss=5.51729 epoch 13; steps=30000/38898; loss=5.38389 epoch 13 ; lr=0.00125; loss=5.77996 epoch 14; steps= 0/38898; loss=5.74729 epoch 14; steps=10000/38898; loss=5.51249 epoch 14; steps=20000/38898; loss=5.22044 epoch 14; steps=30000/38898; loss=5.34987 epoch 14 ; lr=0.00125; loss=5.80022 epoch 15; steps= 0/38898; loss=5.64972 epoch 15; steps=10000/38898; loss=5.41167 epoch 15; steps=20000/38898; loss=5.41378 epoch 15; steps=30000/38898; loss=5.53267 epoch 15 ; lr=0.000625; loss=5.23845 epoch 16; steps= 0/38898; loss=5.24246 epoch 16; steps=10000/38898; loss=5.39503 epoch 16; steps=20000/38898; loss=5.67561 epoch 16; steps=30000/38898; loss=5.37725 epoch 16 ; lr=0.000625; loss=5.23388 epoch 17; steps= 0/38898; loss=5.82594 epoch 17; steps=10000/38898; loss=5.79435 epoch 17; steps=20000/38898; loss=4.98136 epoch 17; steps=30000/38898; loss=5.16951 epoch 17 ; lr=0.000625; loss=5.35618 epoch 18; steps= 0/38898; loss=5.62355 epoch 18; steps=10000/38898; loss=5.68160 epoch 18; steps=20000/38898; loss=5.60787 epoch 18; steps=30000/38898; loss=5.37123 epoch 18 ; lr=0.000625; loss=5.47620 epoch 19; steps= 0/38898; loss=5.49577 epoch 19; steps=10000/38898; loss=5.24221 epoch 19; steps=20000/38898; loss=5.09400 epoch 19; steps=30000/38898; loss=5.46962 epoch 19 ; lr=0.000625; loss=5.34219 epoch 20; steps= 0/38898; loss=5.16011 epoch 20; steps=10000/38898; loss=5.82357 epoch 20; steps=20000/38898; loss=5.23138 epoch 20; steps=30000/38898; loss=5.14461 epoch 20 ; lr=0.0003125; loss=5.04264  weights = model.embedding.weight.detach().cpu().numpy() weights.shape  (2103, 30)  Step 6. Create the similarity matrix # similarity = cosine_similarity(weights, weights)  def get_similar_words(input_word: str, n: int): if input_word not in text_processor.w2ix: print(\u0026quot;word not in vocab\u0026quot;) else: input_word_ix = text_processor.w2ix[input_word] similarity_vector = similarity[input_word_ix] most_similar_ixs = np.argsort(similarity_vector)[-n:][::-1] most_similar_words = [(text_processor.ix2w[ix], similarity_vector[ix]) for ix in most_similar_ixs] print(input_word) for word, score in most_similar_words: print(f\u0026quot; \u0026gt; {word}, score={score: .2f}\u0026quot;)  Exploring similar embeddings for some queries \u0026hellip; # get_similar_words(\u0026quot;snape\u0026quot;, 10)  snape \u0026gt; snape, score= 1.00 \u0026gt; lupin, score= 0.84 \u0026gt; dumbledore, score= 0.80 \u0026gt; mcgonagall, score= 0.77 \u0026gt; moody, score= 0.77 \u0026gt; quirrell, score= 0.70 \u0026gt; flitwick, score= 0.68 \u0026gt; professor, score= 0.68 \u0026gt; karkaroff, score= 0.67 \u0026gt; trelawney, score= 0.64  get_similar_words(\u0026quot;vernon\u0026quot;, 10)  vernon \u0026gt; vernon, score= 1.00 \u0026gt; aunt, score= 0.84 \u0026gt; uncle, score= 0.79 \u0026gt; petunia, score= 0.72 \u0026gt; dudley, score= 0.70 \u0026gt; sister, score= 0.60 \u0026gt; furious, score= 0.57 \u0026gt; marge, score= 0.57 \u0026gt; throat, score= 0.54 \u0026gt; madly, score= 0.51  get_similar_words(\u0026quot;muggle\u0026quot;, 10)  muggle \u0026gt; muggle, score= 1.00 \u0026gt; wizarding, score= 0.72 \u0026gt; old, score= 0.62 \u0026gt; n, score= 0.61 \u0026gt; greatest, score= 0.61 \u0026gt; protection, score= 0.59 \u0026gt; unusual, score= 0.58 \u0026gt; born, score= 0.58 \u0026gt; pure, score= 0.58 \u0026gt; young, score= 0.57  get_similar_words(\u0026quot;harry\u0026quot;, 10)  harry \u0026gt; harry, score= 1.00 \u0026gt; ron, score= 0.71 \u0026gt; hermione, score= 0.67 \u0026gt; he, score= 0.56 \u0026gt; malfoy, score= 0.52 \u0026gt; hagrid, score= 0.50 \u0026gt; then, score= 0.49 \u0026gt; moody, score= 0.48 \u0026gt; furiously, score= 0.47 \u0026gt; lupin, score= 0.46  get_similar_words(\u0026quot;granger\u0026quot;, 10)  granger \u0026gt; granger, score= 1.00 \u0026gt; miss, score= 0.74 \u0026gt; girl, score= 0.67 \u0026gt; honestly, score= 0.66 \u0026gt; finnigan, score= 0.65 \u0026gt; rosmerta, score= 0.64 \u0026gt; oliver, score= 0.63 \u0026gt; shrieked, score= 0.63 \u0026gt; ernie, score= 0.63 \u0026gt; shortly, score= 0.62  get_similar_words(\u0026quot;slytherin\u0026quot;, 10)  slytherin \u0026gt; slytherin, score= 1.00 \u0026gt; gryffindor, score= 0.78 \u0026gt; hufflepuff, score= 0.77 \u0026gt; team, score= 0.76 \u0026gt; goal, score= 0.72 \u0026gt; ravenclaw, score= 0.72 \u0026gt; heir, score= 0.69 \u0026gt; quidditch, score= 0.68 \u0026gt; points, score= 0.68 \u0026gt; irish, score= 0.68  get_similar_words(\u0026quot;malfoy\u0026quot;, 10)  malfoy \u0026gt; malfoy, score= 1.00 \u0026gt; lucius, score= 0.68 \u0026gt; diggory, score= 0.67 \u0026gt; draco, score= 0.67 \u0026gt; goyle, score= 0.66 \u0026gt; crouch, score= 0.65 \u0026gt; crabbe, score= 0.62 \u0026gt; percy, score= 0.59 \u0026gt; mr, score= 0.58 \u0026gt; weasley, score= 0.57  The results should improve easily with more training as we are already seeing good results for a lot of the input words like snape for which it shows other hogwarts professors etc.\nWe will try to train on more data by using negative sampling to train faster and hopefully be able to improve the embeddings.\nFor detailed intro to Word2Vec and word vectors in general, check out these awesome resources. Most of the work here has derived from these materials.\n Stanford 2021 nlp lecture Yandex nlp course  "}).add({id:2,href:"/blog/mlops-template-part-4-fastapi-elasticapm/",title:"MLOps template [Part 4] · FastAPI + ElasticAPM",description:"We will use FastAPI to serve our trained models behind a REST endpoint.",content:"Scripts related to the APIs are located at MLOps/app.\n├── application.py # FastAPI app and launcher uvicorn.run ├── models # pydantic model for reponse validation │ └── predict.py # pydantic model for predict endpoint └── routes # to maintain larger applications ├── endpoints │ └── predict.py # predict endpoint └── router.py # APIRouter module to maintain larger apps  Though we have used the APIRouter module here, it\u0026rsquo;s really needed when we have lots of API endpoints in a larger app.\nLook at https://fastapi.tiangolo.com/tutorial/bigger-applications/\nModel Artifacts # To use the model to get predictions, we need to load all the model related artifacts.\nWe load the trained model directly using the mlflow.sklearn module. Here we load the version number 1 of our sk-learn-naive-bayes-clf-model model.\n# manually pick the model version from trained models sk_model = mlflow.sklearn.load_model(model_uri=\u0026quot;models:/sk-learn-naive-bayes-clf-model/1\u0026quot;) # mlflow does not store data manipulation routines like label encoding # we need to manage the LabelEncoder and TfidfVectorizer ourselves with open(BASE_DIR / \u0026quot;artifacts/target_encoder.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: target_encoder = pickle.load(f) with open(BASE_DIR / \u0026quot;artifacts/vectorizer.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: vectorizer = pickle.load(f) logger.info(\u0026quot;Loaded model artifacts\u0026quot;)  Beyond the trained classifier, we also need the TfidfVectorizer to vectorize the text and LabelEncoder to map the predictions to actual labels.\nThese artifacts are not saved/managed by MLflow as it only mangages the artifacts realted to the ML algorithm. #\n Exclude certain preprocessing \u0026amp; feature manipulation estimators from patching. These estimators represent data manipulation routines (e.g., normalization, label encoding) rather than ML algorithms. Accordingly, we should not create MLflow runs and log parameters / metrics for these routines, unless they are captured as part of an ML pipeline (via sklearn.pipeline.Pipeline)\n # manually pick the model version from trained models sk_model = mlflow.sklearn.load_model(model_uri=\u0026quot;models:/sk-learn-naive-bayes-clf-model/1\u0026quot;) # mlflow does not store data manipulation routines like label encoding # we need to manage the TfidfVectorizer and TfidfVectorizer ourselves with open(BASE_DIR / \u0026quot;artifacts/target_encoder.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: target_encoder = pickle.load(f) with open(BASE_DIR / \u0026quot;artifacts/vectorizer.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: vectorizer = pickle.load(f) logger.info(\u0026quot;Loaded model artifacts\u0026quot;)  Predict Endpoint # # Let\u0026rsquo;s look at the /predict endpoint.\n@router.post(\u0026quot;/predict\u0026quot;) async def predit(text: str) -\u0026gt; PredictResponseModel: logger.info(f\u0026quot;Received text for prediction: {text}\u0026quot;) processed_text_list = preprocess_text([text]) x = vectorizer.transform(processed_text_list) pred = sk_model.predict_proba(x) mapped_pred = dict(zip(target_encoder.classes_, pred[0])) logger.info(f\u0026quot;Prediction: {mapped_pred}\u0026quot;) return PredictResponseModel(preds=mapped_pred).preds  Here, we preprocess the text using preprocess_text(), vectorize it using vectorizer.transform() and finally generate predictions using the classifier sk_model.predict_proba().\nWe then map the probabilities to the actual labels(target_encoder.classes_) and return the predictions by wrapping around the PredictResponseModel pydantic model for data validation.\nThe API can be accessed at http://127.0.0.1:8010/docs.\n  ElasticAPM # We have also added ElasticAPM as a middleware for monitoring our FastAPI application. #\nimport uvicorn from elasticapm.contrib.starlette import ElasticAPM, make_apm_client from fastapi import FastAPI from loguru import logger from mlops.app.routes.router import api_router def get_fastapi_application() -\u0026gt; FastAPI: application = FastAPI(title=\u0026quot;MLOps\u0026quot;) application.add_middleware( ElasticAPM, client=make_apm_client({\u0026quot;SERVICE_NAME\u0026quot;: \u0026quot;MLOps Example\u0026quot;}) ) application.include_router(api_router) return application app = get_fastapi_application() if __name__ == \u0026quot;__main__\u0026quot;: logger.info(\u0026quot;*** Starting Prediction Server ***\u0026quot;) uvicorn.run(app, host=\u0026quot;127.0.0.1\u0026quot;, port=8010)  Once we start using the /predict endpoint, we can head over to http://localhost:5601/ to look at the app related metrics like Latency, Throughput etc, and system level metrics like CPU usage and System memory usage.\n    Under the hood, it uses Elastic Search, Kibana and an APM server launched using the docker-compose-monitoring.yaml during the setup.\nThe dashboard also provides a trace for each request.\n"}).add({id:3,href:"/blog/mlops-template-part-3-mlflow-minio/",title:"MLOps template [Part 3] · MLflow + MinIO",description:"In the last part, we saw our pipeline at the end. Steps 1-5 deal with data manipulation. We train our model in step 6 and that's where `MLflow` comes into picture.",content:"@pipeline def ml_pipeline(): # 1. fetch training data texts, target = get_training_dataset() # 2. minimal text preprocessing # 3. tfidf vectorization vectorizer, X = get_vectorizer_and_features(preprocess_text(texts)) # 4. target encoding target_encoder, encoded_target = get_targetencoder_and_encoded_targets(target) # 5. train test split X_train, X_test, y_train, y_test = train_test_split(X, encoded_target) # 6. model training, validation, registry, artifact storage train_clf(X_train, X_test, y_train, y_test)  MLflow # #  MLflow is an open source platform for managing the end-to-end machine learning lifecycle. It tackles four primary functions:\nTracking experiments to record and compare parameters and results (MLflow Tracking).\nPackaging ML code in a reusable, reproducible form in order to share with other data scientists or transfer to production (MLflow Projects).\nManaging and deploying models from a variety of ML libraries to a variety of model serving and inference platforms (MLflow Models).\nProviding a central model store to collaboratively manage the full lifecycle of an MLflow Model, including model versioning, stage transitions, and annotations (MLflow Model Registry).\n For our usecase, we mainly focus on Mlflow Tracking and Mlflow Registry. train_clf() internally calls train_and_validate_clf() located at mlops/ml_workflow/naive_bayes_clf.py.\nThis script has as all the MLflow components and we will look at those in detail.\nTracking # # # setting env vars for minio artifact storage set_env_vars() mlflow.set_tracking_uri(os.getenv(\u0026quot;MLFLOW_TRACKING_URI\u0026quot;)) # creates a new mlflow experiment MLFLOW_EXPERIMENT_NAME if it doesn't exist exps = [exp.name for exp in mlflow.tracking.MlflowClient().list_experiments()] if not os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;) in exps: mlflow.create_experiment( os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;), artifact_location=os.getenv(\u0026quot;MLFLOW_ARTIFACT_LOCATION\u0026quot;), )   MLflow runs can be recorded to local files, to a SQLAlchemy compatible database, or remotely to a tracking server. By default, the MLflow Python API logs runs locally to files in an mlruns directory wherever you ran your program. You can then run mlflow ui to see the logged runs.\nTo log runs remotely, set the MLFLOW_TRACKING_URI environment variable to a tracking server’s URI or call mlflow.set_tracking_uri().\nThere are different kinds of remote tracking URIs:\n Local file path (specified as file:/my/local/dir), where data is just directly stored locally. Database encoded as +://:@:/. MLflow supports the dialects mysql, mssql, sqlite, and postgresql. For more details, see SQLAlchemy database uri. HTTP server (specified as https://my-server:5000), which is a server hosting an MLflow tracking server. Databricks workspace (specified as databricks or as databricks://, a Databricks CLI profile. Refer to Access the MLflow tracking server from outside Databricks [AWS] [Azure], or the quickstart to easily get started with hosted MLflow on Databricks Community Edition.   We use sqlite for tracking. MLFLOW_TRACKING_URI=sqlite:///mlflow.db. This file stays at the root directory of the project.\n You can optionally organize runs into experiments, which group together runs for a specific task. You can create an experiment using the mlflow experiments CLI, with mlflow.create_experiment(), or using the corresponding REST parameters. The MLflow API and UI let you create and search for experiments.\n # setting env vars for minio artifact storage set_env_vars() mlflow.set_tracking_uri(os.getenv(\u0026quot;MLFLOW_TRACKING_URI\u0026quot;)) # creates a new mlflow experiment MLFLOW_EXPERIMENT_NAME if it doesn't exist exps = [exp.name for exp in mlflow.tracking.MlflowClient().list_experiments()] if not os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;) in exps: mlflow.create_experiment( os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;), artifact_location=os.getenv(\u0026quot;MLFLOW_ARTIFACT_LOCATION\u0026quot;), )  First time we execute the pipeline, experiment MLFLOW_EXPERIMENT_NAME=MLOps is created and is used for subsequent runs.\ndef train_and_validate_clf( X_train: np.array, X_test: np.array, y_train: np.array, y_test: np.array ) -\u0026gt; str: mlflow.set_experiment(os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;)) with mlflow.start_run(run_name=\u0026quot;NAIVE_BAYES_CLF\u0026quot;): # ignoring rest of the script pass  Registry # # Under an experiment, we can log metrics, log model parameters, save and version model artifacts. These steps come under the purview of model-registry. Here, we log\n classifier parameter alpha classification metrics precision, recall and f1_score  We also save and version the model using mlflow.sklearn.log_model. Each subsequent run of the pipeline with the same artifact_path and registered_model_name increases the model version by 1 in the registry.\ndef train_and_validate_clf( X_train: np.array, X_test: np.array, y_train: np.array, y_test: np.array ) -\u0026gt; str: mlflow.set_experiment(os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;)) with mlflow.start_run(run_name=\u0026quot;NAIVE_BAYES_CLF\u0026quot;): clf = MultinomialNB() mlflow.log_param(\u0026quot;alpha\u0026quot;, clf.get_params()[\u0026quot;alpha\u0026quot;]) clf.fit(X_train, y_train) y_pred = clf.predict(X_test) scores = precision_recall_fscore_support(y_test, y_pred, average=\u0026quot;weighted\u0026quot;) mlflow.log_metric(\u0026quot;precision\u0026quot;, scores[0]) mlflow.log_metric(\u0026quot;recall\u0026quot;, scores[1]) mlflow.log_metric(\u0026quot;f1_score\u0026quot;, scores[2]) mlflow.sklearn.log_model( sk_model=clf, artifact_path=\u0026quot;naive-bayes-model\u0026quot;, registered_model_name=\u0026quot;sk-learn-naive-bayes-clf-model\u0026quot;, ) return classification_report(y_test, y_pred)  Heading over to the experiment section at http://127.0.0.1:5000, we can see the registry entry for each of our runs, along with the logged metrics and model parameters.\n  For each run, we can also look at the artifact location.\n  When we created the experiment, we speficified artifact_location=os.getenv(\u0026quot;MLFLOW_ARTIFACT_LOCATION\u0026quot;) where MLFLOW_ARTIFACT_LOCATION=s3://mlflow. Internally, this stores the model artifacts locally at the directory minio_data we created during the setup.\nWe can head over to http://127.0.0.1:9001/buckets/mlflow/browse to look at the saved model artifacts.\n  In the next part, we will look at serving the trained model being a REST endpoint.\n"}).add({id:4,href:"/blog/mlops-template-part-2-dagster-pipeline/",title:"MLOps template [Part 2] · Dagster Pipeline",description:"Here we will cover our small pipeline written in dagster.",content:" Dagster is a data orchestrator for machine learning, analytics, and ETL\n Dagster is a second generation data orchestrator that focues on being data-driven rather than task-driven(like Airflow).\nSolids and Pipelines # #  Dagster\u0026rsquo;s core abstractions are solids and pipelines.\n  Solids are individual units of computation that we wire together to form pipelines. By default, all solids in a pipeline execute in the same process. In production environments, Dagster is usually configured so that each solid executes in its own process.\n Dataset # Our pipeline will operate on Question Type Classification. This data helps to classify the given Questions into respective categories based on what type of answer it expects such as a numerical answer or a text description or a place or human name etc.\n   Question Category     How did serfdom develop in and then leave Russia ? DESCRIPTION   What films featured the character Popeye Doyle ? ENTITY   How can I find a list of celebrities ' real names ? DESCRIPTION   What fowl grabs the spotlight after the Chinese Year of the Monkey ? ENTITY   What is the full form of .com ? ABBREVIATION   What contemptible scoundrel stole the cork from my lunch ? HUMAN   What team did baseball \u0026rsquo;s St. Louis Browns become ? HUMAN    Category can take following values - HUMAN, ENTITY, DESCRIPTION, NUMERIC, LOCATION.\nSolid # #  A solid is a unit of computation in a data pipeline. Typically, you\u0026rsquo;ll define solids by annotating ordinary Python functions with the @solid decorator.\n Our first solid get_training_dataset loads the data from csv and returns\n texts (List[str]) - Question target (List[str]) - Category  @solid( output_defs=[ OutputDefinition(name=\u0026quot;texts\u0026quot;, is_required=True), OutputDefinition(name=\u0026quot;target\u0026quot;, is_required=True), ] ) def get_training_dataset(context): texts, target = dataloaders.get_input_dataset(INPUT_DATASET_LOC) context.log.info(f\u0026quot;Loaded data; N={len(texts)}, Targets={set(target)}\u0026quot;) yield Output(texts, \u0026quot;texts\u0026quot;) yield Output(target, \u0026quot;target\u0026quot;)  OutputDefinition # #  To define multiple outputs, or to use a different output name than \u0026ldquo;result\u0026rdquo;, you can provide OutputDefinitions to the @solid decorator.\nWhen you have more than one output, you must yield an instance of the Output class to disambiguate between outputs.\n Let\u0026rsquo;s look at another solid preprocess_text.\n@solid def preprocess_text(context, texts): texts = text_preprocessing.preprocess_text(texts) context.log.info(f\u0026quot;Text pre-processing done; N={len(texts)}\u0026quot;) return texts  Here, we are doing some text preprocessing. Since we are not returning mulitple outputs here, we can avoid OutputDefinition.\nPipeline # #  To execute our solid, we\u0026rsquo;ll embed it in an equally simple pipeline. A pipeline is a set of solids arranged into a DAG of computation. You\u0026rsquo;ll typically define pipelines by annotating ordinary Python functions with the @pipeline decorator.\n Let\u0026rsquo;s look at our Pipeline.\n@pipeline def ml_pipeline(): # 1. fetch training data texts, target = get_training_dataset() # 2. minimal text preprocessing # 3. tfidf vectorization vectorizer, X = get_vectorizer_and_features(preprocess_text(texts)) # 4. target encoding target_encoder, encoded_target = get_targetencoder_and_encoded_targets(target) # 5. train test split X_train, X_test, y_train, y_test = train_test_split(X, encoded_target) # 6. model training, validation, registry, artifact storage train_clf(X_train, X_test, y_train, y_test)  Here we call few solids like get_training_dataset, preprocess_text, get_vectorizer_and_features, etc.\nThese calls don\u0026rsquo;t actually execute the solids. Within the bodies of functions decorated with @pipeline, we use function calls to indicate the dependency structure of the solids making up the pipeline.\nExecuting Our First Pipeline # # Dagit to visualize our pipeline in Dagit, from the directory in which we have saved the pipeline file.\n$ dagit -f mlops/pipeline.py # Loading repository... Serving on http://127.0.0.1:3000  We can head over to the browser and look at the pipeline.\n  To execute the pipeline from the UI, head over to the playground section and click Launch Execution (at the bottom right).\nIf the pipeline executed successfully, you should see logs like this.\n  The pipeline we just executed registered our trained model using MLflow and stored the model artifacts using minio.\nWe will look at those components in the next part.\n"}).add({id:5,href:"/blog/mlops-template-part-1-setup/",title:"MLOps template [Part 1] · Setup",description:"In this series of posts, we will take a small dataset and go through various steps like building Data pipelines, ML workflow management, API development and Monitoring.",content:"These steps are necessary for operationalization of any machine-learning based model.\nThese posts are in no way exhaustive in covering the breadth of MLOps.\nSeveral key pieces like the CI/CD pipeline, monitoring for drift, etc are missing at the moment, which might get added later.  Stack # We will be using the following tools in this project\n Data Pipeline: Dagster ML registry: MLflow API Development: FastAPI Monitoring: ElasticAPM  Dev Setup # Poetry # # $ curl -sSL https://raw.githubusercontent.com/python-poetry/poetry/master/get-poetry.py | python - $ poetry --version # Poetry version 1.1.10  pre-commit # # $ pip install pre-commit $ pre-commit --version # pre-commit 2.15.0  Minio # Follow the instructions here - Minio installation.\nFor Mac users\nbrew install minio/stable/minio  Install python packages # $ poetry install # Installing dependencies from lock file # No dependencies to install or update # Installing the current project: mlops (0.1.0)  MLflow # $ poetry shell $ export MLFLOW_S3_ENDPOINT_URL=http://127.0.0.1:9000 $ export AWS_ACCESS_KEY_ID=minioadmin $ export AWS_SECRET_ACCESS_KEY=minioadmin # make sure that the backend store and artifact locations are same in the .env file as well $ mlflow server \\ --backend-store-uri sqlite:///mlflow.db \\ --default-artifact-root s3://mlflow \\ --host 0.0.0.0    MinIO # $ export MINIO_ROOT_USER=minioadmin $ export MINIO_ROOT_PASSWORD=minioadmin $ mkdir minio_data $ minio server minio_data --console-address \u0026quot;:9001\u0026quot; # API: http://192.168.29.103:9000 http://10.119.80.13:9000 http://127.0.0.1:9000 # RootUser: minioadmin # RootPass: minioadmin # Console: http://192.168.29.103:9001 http://10.119.80.13:9001 http://127.0.0.1:9001 # RootUser: minioadmin # RootPass: minioadmin # Command-line: https://docs.min.io/docs/minio-client-quickstart-guide # $ mc alias set myminio http://192.168.29.103:9000 minioadmin minioadmin # Documentation: https://docs.min.io  Go to http://127.0.0.1:9001/buckets/ and create a bucket called mlflow.\n  Dagster # $ poetry shell $ dagit -f mlops/pipeline.py    ElasticAPM # $ docker-compose -f docker-compose-monitoring.yaml up    FastAPI # $ poetry shell $ export PYTHONPATH=. $ python mlops/app/application.py    "}),search.addEventListener('input',b,!0);function b(){var b,e;const d=5;b=this.value,e=a.search(b,{limit:d,enrich:!0});const c=new Map;for(const a of e.flatMap(a=>a.result)){if(c.has(a.doc.href))continue;c.set(a.doc.href,a.doc)}if(suggestions.innerHTML="",suggestions.classList.remove('d-none'),c.size===0&&b){const a=document.createElement('div');a.innerHTML=`No results for "<strong>${b}</strong>"`,a.classList.add("suggestion__no-results"),suggestions.appendChild(a);return}for(const[h,g]of c){const b=document.createElement('div');suggestions.appendChild(b);const a=document.createElement('a');a.href=h,b.appendChild(a);const e=document.createElement('span');e.textContent=g.title,e.classList.add("suggestion__title"),a.appendChild(e);const f=document.createElement('span');if(f.textContent=g.description,f.classList.add("suggestion__description"),a.appendChild(f),suggestions.appendChild(b),suggestions.childElementCount==d)break}}})()